var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"자율 전투함 엑시노아, 피격 확인! 침몰합니다!","JPN":"自律戦闘艦エキシノア、ダメージを確認！　沈没します！","ENG":"Confirmed hit on autonomous battleship Axinoa! Ship destroyed!","TWN":"自動戰鬥艦 艾西諾瓦確認遭到擊落！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"상관없어! 보조함들은 전부 엔터프라이즈의 방패로 사용할 테니까!","JPN":"構わない！　補助艦船はすべてエンタープライズの盾に使うから！","ENG":"It doesn’t matter! We’re gonna use the support ships as shields for the Enterprise!","TWN":"無所謂！輔助艦可以全部拿來當作企業號的盾牌！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쿼드 엔진이 재가동될 때까지는 어떻게든 버텨야 해!","JPN":"クワッドエンジンが再稼働するまではなんとか耐えないと！","ENG":"Hold on until the Quad Engines come back online!","TWN":"4號引擎重新啟動前，不管怎麼樣都要撐住！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"다크 세븐 멍청이들! 아직 멀었어?","JPN":"ダークセブンのバカたち！　まだなの？","ENG":"Hey, Dark Seven dummies! How much longer?!","TWN":"Dark 7的笨蛋們！還沒好嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"지금 커피도 없이 제어 코드를 6만줄째 짜고 있다고…… 더, 더 이상은 무리야……","JPN":"今コーヒーなしで制御コードを6万行も書いてるんだよ……も、もうこれ以上は無理……","ENG":"We’re writing our 60,000th control code without coffee... W-we’re dying down here...","TWN":"控制碼都已經寫到第6萬行，連咖啡都不給一杯……是要怎麼寫下去啦……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"뭔 놈의 함선에 커피 포트 하나 없는 거야, 대체?!","JPN":"艦船にコーヒーポット一つもないなんて、どうなってるんだ！？","ENG":"What kind of ship doesn’t have a single coffeepot?!","TWN":"怎麼會有人的艦船連個咖啡壺都沒有，合理嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"프로그래머에게 커피와 초콜렛을 지급하지 않는 건 인권 침해라고!","JPN":"プログラマーにコーヒーとチョコレートを支給しないのは人権侵害だ！","ENG":"Not supplying programmers with coffee and chocolates is a human rights violation!","TWN":"不提供咖啡跟巧克力，是侵害工程師的人權好嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"끈질기게도 몰려오네! 대체 어디까지 퇴각하란 거야?","JPN":"しつこいな！　一体どこまで退却しろってんだ？","ENG":"They just keep on coming! How much farther are we going to retreat?","TWN":"一直撲過來欸！到底是要退到哪裡啦？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"애초에 여긴 이면세계잖아? 물러난다고 뭐가 나올 리가 없는데!","JPN":"大体ここは裏世界だろ？　下がったってなんも出ないじゃん！","ENG":"I mean, we’re in Counterside, right? Retreating isn’t going to get us anywhere!","TWN":"這裡不是異界嗎？怎麼會一直有東西冒出來！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님과 중장님께 뭔가 계획이 있겠지.","JPN":"副社長と中将に何か考えがあるんでしょ。","ENG":"The Vice President and Lieutenant General must have a plan.","TWN":"副總和中將應該在計畫什麼吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그때까지 시간을 버는 게 우리 일이야.","JPN":"その時まで時間を稼ぐのが私たちの仕事だよ。","ENG":"Our job is to buy them the time that they need.","TWN":"在那之前，我們的任務是爭取時間。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러니까 정신 똑바로 차려! 화살이 계속 엉뚱한 데로 날아가잖아!","JPN":"だからしっかりしなさい！　矢が変なところに飛んでるじゃない！","ENG":"So stop complaining and focus! Your arrows keep missing!","TWN":"大家給我振作一點！箭一直射歪是怎樣！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죄, 죄송해요. 서윤 씨. 침식파 때문에 조준이 계속 빗나가는 것 같아요.","JPN":"す、すみません。アオイさん。侵食波のせいでずれてるみたいです。","ENG":"S-sorry, Miss Seo Yoon. I think my aim keeps going off because of the Corruption ray.","TWN":"抱…抱歉，徐芸。因為侵蝕波的關係，害我一直瞄不準。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하! 침식파 같은 소리 하네!","JPN":"は！　侵食波ぁ？","ENG":"Ha! Seriously? Corruption ray?","TWN":"哈！竟敢給我扯什麼侵蝕波！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그게 다 정신 상태가 불량해서 그런 거야! 내가 교육 받을 땐 어땠는지 알아?!","JPN":"それは精神状態がダメだからなのよ！　私が教育された時はどうだったかわかってる！？","ENG":"That’s because you all had it so easy! Do you have any idea what my lesson was like?!","TWN":"怪只能怪你自己的心理素質不佳！你知道我受到的是什麼樣的教育嗎？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죄송합니다! 죄송해요!!","JPN":"すみません！　すみません！！","ENG":"I'm sorry! I'm sorry!","TWN":"對不起！對不起！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"목소리가 작다!","JPN":"声が小さい！","ENG":"I can’t hear you!","TWN":"太小聲！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"전 멍청이에요! 무능한 주제에 겁없이 기어나온 해삼 내장이에요!","JPN":"私はバカです！　無能なくせに大胆に這い出てきたナマコの内臓です！","ENG":"I’m an idiot sandwich! I’m a useless, cowardly sack of potatoes!","TWN":"我是笨蛋！沒用還出來丟人現眼！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐야? 저 여자…… 리플레이서 퀸 아니야?","JPN":"なんだ？　あの女……リプレイサー・クイーンじゃないか？","ENG":"What the heck? That girl... Isn’t she the Replacer Queen?","TWN":"是怎樣？她……不是克隆·女皇嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그 괴물이 왜 저렇게 얼빠지게 구는 건지 모르겠지만…… 대장도 좀 심한 것 같은데.","JPN":"あのバケモンがなんであんなボケてるのかはわかんないけど……隊長もちょっとひどいな。","ENG":"I don’t know why that monster is acting so stupid, but I think Cap is taking things too far.","TWN":"雖然不知道那個怪物怎麼那麼笨手笨腳的……不過隊長會不會太兇啦？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭔가 악에 받혀 있다고 해야 하나?","JPN":"なんか怒り狂ってる感じ？","ENG":"Not sure how to put it... But it’s almost as if she’s enraged.","TWN":"整個往死裡罵欸？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"……고개 돌려, 멍청아. 나라면 지금 대장이랑 눈 마주치지 않을 거야.","JPN":"……見るな、アホ。私だったら今の隊長とは目も合わせない。","ENG":"...Stop staring at her you idiot. I wouldn’t lock eyes with Cap right now if I were you.","TWN":"……還不快轉頭，你這傻瓜，要是我，現在才不敢和隊長對到眼。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};